1	/**
2	 * Tool Loop — iterative tool call execution for DirectProvider.
3	 *
4	 * Safety guards:
5	 * 1. Iteration limit (default 25)
6	 * 2. Repetition detection (same tool+args ≥3 times → break)
7	 * 3. Parallel tool execution (Promise.all for multi-tool responses)
8	 */
9	import { createHash } from "node:crypto";
10	import { existsSync } from "node:fs";
11	import { resolve, dirname } from "node:path";
12	import type { McpPool } from "./mcp-pool.js";
13	import { enrichCodegraphResult } from "./codegraph-enricher.js";
14	
15	// ─── Types shared with adapters ────────────────────────────────────────────
16	
17	export interface ChatMessage {
18	  role: "system" | "user" | "assistant" | "tool";
19	  content: string | ContentBlock[];
20	  tool_call_id?: string;
21	  tool_calls?: ToolCall[];
22	}
23	
24	export interface ContentBlock {
25	  type: "text" | "tool_use" | "tool_result";
26	  text?: string;
27	  id?: string;
28	  name?: string;
29	  input?: Record<string, unknown>;
30	  tool_use_id?: string;
31	  content?: string;
32	  is_error?: boolean;
33	}
34	
35	export interface ToolCall {
36	  id: string;
37	  type: "function";
38	  function: { name: string; arguments: string };
39	}
40	
41	export interface ToolDef {
42	  type: "function";
43	  function: {
44	    name: string;
45	    description?: string;
46	    parameters: Record<string, unknown>;
47	  };
48	}
49	
50	/** Adapter must implement this to be used by the tool loop. */
51	export interface LlmAdapter {
52	  chat(messages: ChatMessage[], opts: {
53	    tools?: ToolDef[];
54	    onText?: (chunk: string) => void;
55	    onThinking?: (chunk: string) => void;
56	  }): Promise<{ message: ChatMessage; stopReason: string }>;
57	}
58	
59	// ─── Tool Loop ─────────────────────────────────────────────────────────────
60	
61	export interface ToolLoopOptions {
62	  maxIterations?: number;
63	  /** Context window size — enables mid-loop overflow protection. */
64	  contextWindow?: number;
65	  /** Max chars per tool result (truncated if exceeded). Default: unlimited. */
66	  maxToolResultChars?: number;
67	  onText?: (chunk: string) => void;
68	  onThinking?: (chunk: string) => void;
69	  onToolStart?: (name: string, input: string) => void;
70	  onToolEnd?: (name: string, result: string, isError: boolean) => void;
71	}
72	
73	const DEFAULT_MAX_ITERATIONS = 25;
74	const REPETITION_THRESHOLD = 3;
75	const RTK_ENABLED = ["true", "1"].includes(process.env.RTK_SHELL_REWRITE ?? "");
76	
77	export async function runToolLoop(
78	  adapter: LlmAdapter,
79	  pool: McpPool,
80	  messages: ChatMessage[],
81	  tools: ToolDef[],
82	  opts: ToolLoopOptions = {},
83	): Promise<{ stopReason: string }> {
84	  const maxIter = opts.maxIterations ?? DEFAULT_MAX_ITERATIONS;
85	  const recentCalls: string[] = []; // hashes of recent tool calls
86	
87	  for (let i = 0; i < maxIter; i++) {
88	    // Mid-loop context overflow protection: if messages exceed 85% of context window, break early
89	    if (opts.contextWindow) {
90	      const currentTokens = estimateMessagesTokens(messages);
91	      if (currentTokens > opts.contextWindow * 0.85) {
92	        console.warn(`[tool-loop] context overflow guard: ${currentTokens} tokens > 85% of ${opts.contextWindow} — breaking at iteration ${i}`);
93	        messages.push({
94	          role: "assistant",
95	          content: "[System: Context budget nearly exhausted. Summarize progress and respond now.]",
96	        });
97	        const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
98	        messages.push(final.message);
99	        return { stopReason: "context_overflow" };
100	      }
101	    }
102	
103	    const { message, stopReason } = await adapter.chat(messages, {
104	      tools,
105	      onText: opts.onText,
106	      onThinking: opts.onThinking,
107	    });
108	
109	    messages.push(message);
110	
111	    // Extract tool calls (OpenAI format)
112	    const toolCalls = message.tool_calls;
113	    if (!toolCalls || toolCalls.length === 0) {
114	      return { stopReason };
115	    }
116	
117	    // Repetition detection
118	    for (const tc of toolCalls) {
119	      const hash = hashToolCall(tc.function.name, tc.function.arguments);
120	      recentCalls.push(hash);
121	    }
122	    if (detectRepetition(recentCalls)) {
123	      messages.push({
124	        role: "assistant",
125	        content: "[System: Tool call loop detected — same call repeated multiple times. Please summarize your progress and respond to the user.]",
126	      });
127	      // One more call without tools to get a text response
128	      const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
129	      messages.push(final.message);
130	      return { stopReason: "tool_loop_break" };
131	    }
132	
133	    // Execute tool calls (parallel for different servers, serial for same)
134	    const results = await executeToolCalls(toolCalls, pool, opts);
135	
136	    // Append tool results
137	    for (const r of results) {
138	      messages.push({
139	        role: "tool",
140	        tool_call_id: r.id,
141	        content: r.output,
142	      });
143	    }
144	
145	    // Project auto-detect: hint agent about CodeGraph index and AI.md
146	    const usedCodegraph = toolCalls.some(tc => tc.function.name.startsWith("codegraph_"));
147	    const { codegraph: cgProjects, aiMd: aiProjects } = detectProjectHints(toolCalls);
148	    const hints: string[] = [];
149	
150	    if (!usedCodegraph && cgProjects.length > 0) {
151	      const paths = cgProjects.map(p => `"${p}"`).join(", ");
152	      hints.push(`CodeGraph index detected at ${paths}. Use codegraph_context/codegraph_impact instead of grep for call-chain analysis.`);
153	      for (const p of cgProjects) hintedCodegraph.add(p);
154	    }
155	    if (aiProjects.length > 0) {
156	      const paths = aiProjects.map(p => `${p}/AI.md`).join(", ");
157	      hints.push(`AI.md found at ${paths} — read it for project conventions before making changes.`);
158	      for (const p of aiProjects) hintedAiMd.add(p);
159	    }
160	    if (hints.length > 0) {
161	      messages.push({
162	        role: "assistant",
163	        content: `[System hint: ${hints.join(" | ")}]`,
164	      });
165	    }
166	  }
167	
168	  // Hit iteration limit
169	  messages.push({
170	    role: "assistant",
171	    content: "[System: Maximum tool call iterations reached. Please summarize your progress.]",
172	  });
173	  const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
174	  messages.push(final.message);
175	  return { stopReason: "max_iterations" };
176	}
177	
178	// ─── Helpers ───────────────────────────────────────────────────────────────
179	
180	function hashToolCall(name: string, args: string): string {
181	  return createHash("md5").update(`${name}:${args}`).digest("hex").slice(0, 12);
182	}
183	
184	function detectRepetition(recent: string[]): boolean {
185	  if (recent.length < REPETITION_THRESHOLD) return false;
186	  const last = recent[recent.length - 1];
187	  let count = 0;
188	  for (let i = recent.length - 1; i >= 0 && i >= recent.length - 5; i--) {
189	    if (recent[i] === last) count++;
190	  }
191	  return count >= REPETITION_THRESHOLD;
192	}
193	
194	interface ToolResult {
195	  id: string;
196	  output: string;
197	}
198	
199	async function executeToolCalls(
200	  toolCalls: ToolCall[],
201	  pool: McpPool,
202	  opts: ToolLoopOptions,
203	): Promise<ToolResult[]> {
204	  const results: ToolResult[] = [];
205	  const maxChars = opts.maxToolResultChars;
206	
207	  // Group by server to serialize calls to the same server
208	  // but parallelize across different servers
209	  const tasks = toolCalls.map(async (tc) => {
210	    const name = tc.function.name;
211	    let args: Record<string, unknown>;
212	    try {
213	      args = JSON.parse(tc.function.arguments);
214	    } catch {
215	      args = {};
216	    }
217	
218	    opts.onToolStart?.(name, tc.function.arguments);
219	
220	    // RTK auto-rewrite: prefix shell commands with `rtk` for compressed output
221	    if (RTK_ENABLED && name === "shell" && typeof args.command === "string") {
222	      args.command = applyRtkPrefix(args.command);
223	    }
224	
225	    try {
226	      const result = await pool.callTool(name, args);
227	      
228	      // Codegraph enrichment: 附加 domain 資訊和 wiki 連結
229	      if (name.startsWith("codegraph_")) {
230	        const projectPath = args.projectPath as string | undefined;
231	        enrichCodegraphResult(result, projectPath);
232	      }
233	      
234	      let output = serializeToolResult(result.content);
235	      // Truncate tool output for context-constrained models
236	      if (maxChars && output.length > maxChars) {
237	        output = output.slice(0, maxChars) + `\n...[truncated, ${output.length - maxChars} chars omitted]`;
238	      }
239	      opts.onToolEnd?.(name, output.slice(0, 200), !!result.isError);
240	      return { id: tc.id, output };
241	    } catch (err) {
242	      const errMsg = `Error executing ${name}: ${(err as Error).message}`;
243	      opts.onToolEnd?.(name, errMsg, true);
244	      return { id: tc.id, output: errMsg };
245	    }
246	  });
247	
248	  // Execute all in parallel (MCP SDK handles its own serialization per-connection)
249	  const settled = await Promise.all(tasks);
250	  results.push(...settled);
251	  return results;
252	}
253	
254	function serializeToolResult(content: unknown[]): string {
255	  if (!Array.isArray(content)) return String(content);
256	  return content
257	    .map((block: any) => {
258	      if (block.type === "text") return block.text;
259	      return JSON.stringify(block);
260	    })
261	    .join("\n");
262	}
263	
264	
265	/** Prefix eligible shell commands with `rtk` for compressed output. Skip interactive/piped commands. */
266	function applyRtkPrefix(cmd: string): string {
267	  const trimmed = cmd.trimStart();
268	  // Already has rtk prefix
269	  if (trimmed.startsWith("rtk ")) return cmd;
270	  // Skip: piped chains, interactive commands, redirections
271	  if (/[|><]/.test(cmd)) return cmd;
272	  // Only rewrite known rtk-friendly commands
273	  const rtkCmds = ["git status", "git diff", "git log", "grep ", "cargo test", "npm test", "npx tsc"];
274	  if (rtkCmds.some((c) => trimmed.startsWith(c))) {
275	    return `rtk ${trimmed}`;
276	  }
277	  return cmd;
278	}
279	
280	/** Rough token estimate for mid-loop overflow check. */
281	function estimateMessagesTokens(messages: ChatMessage[]): number {
282	  let chars = 0;
283	  for (const m of messages) {
284	    const c = m.content;
285	    chars += (typeof c === "string" ? c.length : JSON.stringify(c ?? "").length) + 10;
286	  }
287	  return Math.ceil(chars / 4);
288	}
289	
290	// ─── Project auto-detect hints (CodeGraph + AI.md) ─────────────────────────
291	
292	/** Projects where we already emitted a hint this loop (avoid spamming). */
293	const hintedCodegraph = new Set<string>();
294	const hintedAiMd = new Set<string>();
295	
296	/**
297	 * Extract project root paths from tool call args (read/grep/glob paths).
298	 * Walk up to 3 levels from the path to find .codegraph/ or AI.md.
299	 */
300	function detectProjectHints(toolCalls: ToolCall[]): { codegraph: string[]; aiMd: string[] } {
301	  const cgFound: string[] = [];
302	  const aiFound: string[] = [];
303	
304	  for (const tc of toolCalls) {
305	    if (tc.function.name.startsWith("codegraph_")) continue;
306	
307	    let args: Record<string, unknown>;
308	    try { args = JSON.parse(tc.function.arguments); } catch { continue; }
309	
310	    const candidates: string[] = [];
311	    if (typeof args.path === "string") candidates.push(args.path);
312	    if (typeof args.file_path === "string") candidates.push(args.file_path);
313	    if (typeof args.pattern === "string" && /^[A-Z]:[/\\]/.test(args.pattern)) candidates.push(args.pattern);
314	    if (Array.isArray(args.operations)) {
315	      for (const op of args.operations as any[]) {
316	        if (typeof op?.path === "string") candidates.push(op.path);
317	      }
318	    }
319	
320	    for (const p of candidates) {
321	      let dir = resolve(p.replace(/\//g, "\\"));
322	      if (/\.\w+$/.test(dir)) dir = dirname(dir);
323	      for (let depth = 0; depth < 4; depth++) {
324	        const normalized = dir.replace(/\\/g, "/");
325	        if (!hintedCodegraph.has(normalized) && existsSync(resolve(dir, ".codegraph"))) {
326	          cgFound.push(normalized);
327	        }
328	        if (!hintedAiMd.has(normalized) && existsSync(resolve(dir, "AI.md"))) {
329	          aiFound.push(normalized);
330	        }
331	        // Stop walking if we found both at this level
332	        if (cgFound.includes(normalized) && aiFound.includes(normalized)) break;
333	        const parent = dirname(dir);
334	        if (parent === dir) break;
335	        dir = parent;
336	      }
337	    }
338	  }
339	  return { codegraph: [...new Set(cgFound)], aiMd: [...new Set(aiFound)] };
340	}
341	
342	/** Reset hints between sessions (call on session start). */
343	export function resetCodegraphHints(): void {
344	  hintedCodegraph.clear();
345	  hintedAiMd.clear();
346	}
