1	/**
2	 * DirectProvider — calls LLM APIs directly (no ACP subprocess).
3	 * Manages its own MCP connections and tool loop.
4	 */
5	import { EventEmitter } from "node:events";
6	import type { Provider, SessionUpdate, ProviderType } from "./types.js";
7	import { McpPool, loadMcpConfigs, type ToolSchema } from "./mcp-pool.js";
8	import { runToolLoop, type ChatMessage, type ToolDef } from "./tool-loop.js";
9	import { compactIfNeeded } from "./compaction.js";
10	import { detectLlamaCpp, localComplete } from "../local-llm.js";
11	import { OpenAICompatAdapter } from "./adapters/openai-compat.js";
12	import { OllamaNativeAdapter } from "./adapters/ollama-native.js";
13	import { LlamaCppAdapter } from "./adapters/llamacpp.js";
14	import { AnthropicAdapter } from "./adapters/anthropic.js";
15	import type { LlmAdapter } from "./tool-loop.js";
16	
17	export interface DirectProviderConfig {
18	  type: ProviderType;
19	  model: string;
20	  baseUrl: string;
21	  apiKey: string;
22	  /** System prompt (preamble). */
23	  systemPrompt?: string;
24	  /** Extra env vars passed to MCP server processes. */
25	  mcpEnv?: Record<string, string>;
26	  /** If set, only connect MCP servers whose names are in this list. */
27	  mcpServerFilter?: string[];
28	}
29	
30	export class DirectProvider extends EventEmitter implements Provider {
31	  readonly name: string;
32	  private pool = new McpPool();
33	  private adapter: LlmAdapter;
34	  private messages: ChatMessage[] = [];
35	  private tools: ToolDef[] = [];
36	  private _closed = false;
37	  private _inflight = false;
38	  private contextWindow: number;
39	
40	  constructor(private cfg: DirectProviderConfig) {
41	    super();
42	    this.name = cfg.type;
43	    this.adapter = this.createAdapter();
44	    this.contextWindow = resolveContextWindow(cfg.type, cfg.model);
45	  }
46	
47	  private createAdapter(): LlmAdapter {
48	    if (this.cfg.type === "anthropic") {
49	      return new AnthropicAdapter({
50	        apiKey: this.cfg.apiKey,
51	        model: this.cfg.model,
52	        baseUrl: this.cfg.baseUrl || undefined,
53	      });
54	    }
55	    if (this.cfg.type === "local") {
56	      const llamaCppUrl = process.env.LLAMACPP_URL?.trim();
57	      if (llamaCppUrl) {
58	        // llama.cpp server: OpenAI-compatible /v1/chat/completions with <think> tag parsing
59	        console.log(`[direct] using llama.cpp server at ${llamaCppUrl}`);
60	        return new LlamaCppAdapter({ baseUrl: llamaCppUrl, model: this.cfg.model, timeoutMs: 300_000, contextWindow: this.contextWindow });
61	      }
62	      return new OllamaNativeAdapter({
63	        baseUrl: this.cfg.baseUrl.replace(/\/v1$/, ""), // strip /v1 suffix
64	        model: this.cfg.model,
65	        numCtx: Number(process.env.LOCAL_NUM_CTX) || 32768,
66	      });
67	    }
68	    return new OpenAICompatAdapter({
69	      baseUrl: this.cfg.baseUrl,
70	      apiKey: this.cfg.apiKey,
71	      model: this.cfg.model,
72	      numCtx: undefined,
73	    });
74	  }
75	
76	  /** Initialize MCP connections and prepare tool schemas. Returns a session ID. */
77	  async initialize(): Promise<string> {
78	    let configs = await loadMcpConfigs();
79	    if (this.cfg.mcpServerFilter) {
80	      const allow = new Set(this.cfg.mcpServerFilter);
81	      configs = Object.fromEntries(Object.entries(configs).filter(([k]) => allow.has(k)));
82	    }
83	    await this.pool.connectAll(configs, this.cfg.mcpEnv);
84	
85	    // Convert MCP tool schemas to OpenAI function format
86	    this.tools = this.pool.listTools().map(mcpToToolDef);
87	
88	    // Set system prompt
89	    if (this.cfg.systemPrompt) {
90	      this.messages.push({ role: "system", content: this.cfg.systemPrompt });
91	    }
92	
93	    const sessionId = `direct-${Date.now()}`;
94	    console.log(`[direct] initialized "${this.name}" (${this.cfg.model}) — ${this.tools.length} tools from ${this.pool.size} MCP servers`);
95	    return sessionId;
96	  }
97	
98	  async prompt(text: string): Promise<{ stopReason: string }> {
99	    if (this._closed) throw new Error("DirectProvider is closed");
100	    if (this._inflight) throw new Error("Prompt already in progress");
101	    this._inflight = true;
102	
103	    try {
104	      this.messages.push({ role: "user", content: text });
105	
106	      // Context compaction: prevent messages from exceeding model context window
107	      const isLocal = this.cfg.type === "local";
108	      const summarizer = await detectLlamaCpp()
109	        ? async (text: string) => localComplete(
110	            `Summarize this conversation concisely (keep key decisions, tool results, and user requests):\n\n${text.slice(0, 6000)}`,
111	            { maxTokens: 800 },
112	          )
113	        : undefined;
114	      await compactIfNeeded(this.messages, {
115	        contextWindow: this.contextWindow,
116	        threshold: isLocal ? 0.5 : 0.7,
117	        keepTurns: isLocal ? 3 : 5,
118	        summarize: summarizer,
119	      });
120	
121	      const result = await runToolLoop(this.adapter, this.pool, this.messages, this.tools, {
122	        ...(this.cfg.type === "local" ? {
123	          maxIterations: 8,
124	          contextWindow: this.contextWindow,
125	        } : {}),
126	        onText: (chunk) => {
127	          this.emitUpdate("agent_message_chunk", { type: "text", text: chunk });
128	        },
129	        onThinking: (chunk) => {
130	          // Surface thinking text to user as blockquote during streaming.
131	          this.emitUpdate("agent_thought_chunk", { type: "text", text: chunk });
132	        },
133	        onToolStart: (name, input) => {
134	          this.emitUpdate("tool_call", { title: name });
135	        },
136	        onToolEnd: (name, output, isError) => {
137	          this.emitUpdate("tool_call_update", {
138	            toolCallId: name,
139	            status: isError ? "failed" : "completed",
140	          });
141	        },
142	      });
143	
144	      return { stopReason: result.stopReason };
145	    } finally {
146	      this._inflight = false;
147	    }
148	  }
149	
150	  cancel(): void {
151	    // For streaming HTTP, we'd need an AbortController. For now, just mark done.
152	    this._inflight = false;
153	  }
154	
155	  async close(): Promise<void> {
156	    this._closed = true;
157	    await this.pool.close();
158	    this.emit("exit", 0);
159	  }
160	
161	  get isClosed(): boolean {
162	    return this._closed;
163	  }
164	
165	  /** Emit a SessionUpdate event matching the ACP format so run-prompt.ts works unchanged. */
166	  private emitUpdate(sessionUpdate: string, extra: Record<string, unknown>) {
167	    // ACP format wraps message/thought chunks in a `content` field;
168	    // tool_call / tool_call_update fields sit at the top level.
169	    const isChunk = sessionUpdate === "agent_message_chunk" || sessionUpdate === "agent_thought_chunk";
170	    const update = isChunk
171	      ? { sessionUpdate, content: extra }
172	      : { sessionUpdate, ...extra };
173	    const u: SessionUpdate = { sessionId: "direct", update };
174	    this.emit("update", u);
175	  }
176	}
177	
178	// ─── Helpers ───────────────────────────────────────────────────────────────
179	
180	function mcpToToolDef(schema: ToolSchema): ToolDef {
181	  return {
182	    type: "function",
183	    function: {
184	      name: schema.name,
185	      description: schema.description,
186	      parameters: schema.inputSchema,
187	    },
188	  };
189	}
190	
191	/** Resolve provider type to base URL. */
192	export function resolveBaseUrl(type: ProviderType, ollamaUrl: string): string {
193	  switch (type) {
194	    case "anthropic": return "https://api.anthropic.com";
195	    case "openai": return "https://api.openai.com/v1";
196	    case "deepseek": return "https://api.deepseek.com/v1";
197	    case "groq": return "https://api.groq.com/openai/v1";
198	    case "local": return `${ollamaUrl}/v1`;
199	    case "gemini": return "https://generativelanguage.googleapis.com/v1beta/openai";
200	    default: return "https://api.openai.com/v1";
201	  }
202	}
203	
204	
205	/** Approximate context window sizes per provider/model. */
206	function resolveContextWindow(type: ProviderType, model: string): number {
207	  switch (type) {
208	    case "anthropic": return 200_000;
209	    case "openai": return 128_000;
210	    case "gemini": return 1_000_000;
211	    case "deepseek": return 128_000;
212	    case "groq": return 128_000;
213	    case "local": return Number(process.env.LOCAL_CONTEXT_WINDOW) || 32_768;
214	    default: return 128_000;
215	  }
216	}
