1	import { EventEmitter } from "node:events";
2	
3	// ─── Event types ───────────────────────────────────────────────────────────
4	
5	export interface SessionUpdate {
6	  sessionId: string;
7	  update: {
8	    sessionUpdate: string;
9	    [k: string]: unknown;
10	  };
11	}
12	
13	export interface ProviderEvents {
14	  update: [u: SessionUpdate];
15	  stderr: [chunk: string];
16	  exit: [code: number | null];
17	  /** Agent→Client request (ACP only; Direct providers never emit this). */
18	  request: [req: { id: number | string; method: string; params?: unknown }];
19	}
20	
21	// ─── Provider interface ────────────────────────────────────────────────────
22	
23	/**
24	 * Abstraction over the agent backend. Both ACP (subprocess) and Direct
25	 * (LLM API + tool loop) implement this interface so SessionManager and
26	 * run-prompt don't need to know which one is active.
27	 */
28	export interface Provider extends EventEmitter {
29	  /** One-time initialization (connect MCP servers, create ACP session, etc.). Returns session ID. */
30	  initialize(): Promise<string>;
31	  /** Send a user prompt and wait for the turn to complete. Streaming via 'update' events. */
32	  prompt(text: string): Promise<{ stopReason: string }>;
33	  /** Cancel the in-flight prompt. */
34	  cancel(): void;
35	  /** Graceful shutdown. */
36	  close(): Promise<void>;
