167	    // Try to compress recent facts via local LLM (graceful fallback if unavailable)
168	    let compressed: string | null = null;
169	    if (facts && activeType !== "local") {
170	      const lines = facts.split(/\r?\n/).filter(l => l.trim().length > 0);
171	      const tail = config.memoryPreambleTail;
172	      if (lines.length > tail) {
173	        const { compressFactsForPreamble: compress } = await import("./local-llm.js");
174	        compressed = await compress(lines.slice(-tail));
