180	
181	    // Inject working-state from previous session if available (one-shot).
182	    const wsPath = path.join(config.memoryDir, `working-state-${chatId}.md`);
183	    let workingStateBlock = "";
184	    try {
185	      const ws = await readFile(wsPath, "utf8");
186	      workingStateBlock =
187	        "\n[Previous session working state — use as context to resume work]\n" +
188	        ws +
189	        "\nResume from `next_action` above. Do not ask what was done last time.\n" +
190	        "[End working state]\n\n";
191	      await unlink(wsPath);
192	      console.log(`[session] injected working-state for chat ${chatId}`);
193	    } catch { /* file doesn't exist — normal */ }
194	
195	    const relayTaskBlock = await formatActiveRelayTasksForPreamble(chatId);
196	    const preambleText = breakdown.text + workingStateBlock + relayTaskBlock;
197	    const provider = this.createProvider(activeType, env, preambleText);
198	    const session: ChatSession = {
199	      chatId,
200	      userId,
201	      client: provider,
202	      activeProvider: activeType,
203	      sessionId: "",
204	      lastUsed: Date.now(),
205	      buffer: "",
206	      toolLog: [],
207	      stderrTail: "",
208	      history: [],
209	      charsIn: 0,
210	      charsOut: 0,
211	      memoryPreamble: preambleText,
212	      preambleBreakdown: {
213	        total: preambleText.length,
214	        toolNotes: breakdown.toolNotes,
215	        envBlock: breakdown.envBlock,
216	        memoryBlock: breakdown.memoryBlock,
217	        dailylogBlock: breakdown.dailylogBlock,
218	      },
219	      preambleInjected: activeType !== "acp" ? true : false, // Direct providers use system message; ACP needs user-message injection

220	      tailFacts: breakdown.tailFacts,
221	      injectedWikiSlugs: new Set(),
222	      injectedSkills: new Set(),
223	      inflight: false,
224	      _pendingMetaQueue: [],
225	      _consecutiveToolFails: 0,
226	    };
227	
228	    provider.on("update", (u: SessionUpdate) => this.applyUpdate(session, u));
229	    provider.on("stderr", (chunk) => {
230	      // Keep the tail so we can surface it with error messages.
231	      session.stderrTail = (session.stderrTail + chunk).slice(-2000);
232	      // Surface only when debugging; keep quiet otherwise.
233	      if (process.env.DEBUG_ACP) {
234	        console.error(`[acp ${chatId}] ${chunk.trimEnd()}`);
235	      }
236	    });
237	    provider.on("exit", (code) => {
238	      console.error(`[acp ${chatId}] agent exited (code=${code})`);
239	      // Only fire the unexpected-exit hook if this session is still registered.
240	      // Planned shutdowns (drop/sweepIdle/shutdown) remove it from the map first.
241	      const stillRegistered = this.sessions.get(chatId) === session;
242	      if (stillRegistered) {
243	        this.sessions.delete(chatId);
