245	          this.onUnexpectedExit(session, code).catch((e) =>
246	            console.error(`[session ${chatId}] onUnexpectedExit failed:`, e),
247	          );
248	        }
249	      }
250	    });
251	
252	    session.sessionId = await provider.initialize();
253	    this.sessions.set(chatId, session);
254	    logEvent("session_start", { provider: activeType, sessionId: session.sessionId }, { chatId, userId });
255	    return session;
256	  }
