328	  private applyUpdate(session: ChatSession, u: SessionUpdate) {
329	    this.resetInactivityTimer(session);
330	    const up = u.update;
331	    // Opportunistically capture usage-like meta the agent may attach.
332	    const meta = (up as { _meta?: Record<string, unknown> })._meta;
333	    const usage =
334	      (meta?.usage as Record<string, unknown> | undefined) ??
335	      ((up as { usage?: Record<string, unknown> }).usage);
336	    if (usage && typeof usage === "object") {
337	      session.usage = usage;
338	    }
339	    switch (up.sessionUpdate) {
340	      case "agent_message_chunk":
341	      case "agent_thought_chunk": {
342	        const content = up.content as { type?: string; text?: string } | undefined;
343	        if (content?.type === "text" && typeof content.text === "string") {
344	          const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;
345	          if (up.sessionUpdate === "agent_thought_chunk") {
346	            session.thinkingBuffer = (session.thinkingBuffer || "") + content.text;
347	          } else {
348	            session.buffer += content.text;
349	            session.charsOut += content.text.length;
350	          }
351	          if (wasEmpty) petState("streaming");
352	          // Early-capture RELAY_DELEGATE tokens during streaming.
353	          // Workaround: Kiro CLI may strip <<...>> from final text in pure-text turns,
354	          // but streaming chunks arrive unfiltered. We capture complete tokens here
355	          // so the final-render path can fall back to them if normal extraction finds nothing.
356	          // Inline/fenced code examples must stay inert, matching final token extraction.
357	          const captured = captureRelayDelegateTokensFromText(session.buffer, session._streamingDelegates ?? []);
358	          session._streamingDelegates = captured.length ? captured : undefined;
359	          session.onUpdate?.(session);
360	        }
361	        break;
362	      }
363	      case "tool_call": {
364	        const title = (up.title as string) ?? "tool";
365	        const startId = up.toolCallId as string | undefined;
366	        if (startId) (session._toolTitles ??= new Map()).set(startId, title);
367	        session.toolLog.push(`🔧 ${title}`);
368	        session._toolInFlight = true;
369	        petState("tool", title);
370	        session.onUpdate?.(session);
371	        break;
372	      }
373	      case "tool_call_update": {
374	        const status = up.status as string | undefined;
375	        const updId = up.toolCallId as string | undefined;
376	        // tool_call_update carries the opaque toolCallId, not the name. Resolve
377	        // the human-readable title captured at tool_call start; fall back to an
378	        // inline title if the adapter provides one, else "tool".
379	        const toolName =
380	          (updId ? session._toolTitles?.get(updId) : undefined) ??
381	          (up.title as string) ??
382	          "tool";
383	        if (status === "completed") {
384	          session.toolLog.push(`✅ ${toolName}`);
385	          session._toolInFlight = false;
386	          session._consecutiveToolFails = 0;
387	          logEvent("tool_call", { name: toolName, status: "completed" }, { chatId: session.chatId });
388	          if (updId) session._toolTitles?.delete(updId);
389	          session.onUpdate?.(session);
390	        } else if (status === "failed") {
391	          session.toolLog.push(`❌ ${toolName}`);
392	          session._toolInFlight = false;
393	          session._consecutiveToolFails++;
394	          logEvent("tool_call", { name: toolName, status: "failed" }, { chatId: session.chatId });
395	          if (updId) session._toolTitles?.delete(updId);
396	          if (session._consecutiveToolFails >= 2) {
397	            session.toolLog.push(
398	              `⚠️ [Reflexion hint] ${session._consecutiveToolFails} consecutive tool failures. ` +
399	              `STOP and diagnose: what assumption is wrong? Try a different approach.`
400	            );
401	          }
402	          session.onUpdate?.(session);
403	        }
404	        break;
405	      }
406	      default:
407	        // Ignore plan/user_message_chunk/etc. for the bridge.
408	        break;
409	    }
410	  }
